const body = $json.body || $json;
const headers = $json.headers || {};
const configuredToken = String($env.INTERNAL_TEST_TOKEN || '');
const providedToken = String(headers['x-internal-test-token'] || headers['X-Internal-Test-Token'] || body.internal_test_token || '');
const authorized = configuredToken.length >= 24 && providedToken === configuredToken;
return [{ json: {
  authorized,
  tenant_id: body.tenant_id || $env.DEFAULT_TENANT_ID || 'demo',
  channel: 'internal_test',
  thread_id: body.thread_id || body.thread || `internal-${Date.now()}`,
  message_text: body.message_text || body.message || body.text || body.query || body.prompt || '',
  reset: body.reset === true || body.action === 'reset',
  received_at: new Date().toISOString(),
  raw_request: body
}}];

const req = $('Normalize Internal Test Request').first().json;
const state = $json || {};
if (req.reset) {
  return [{ json: { ...req, thread_state: state, reset_requested: true, should_process: false, silent: false } }];
}
const silent = state.status === 'escalated' && state.silence_after_escalation !== false;
return [{ json: { ...req, thread_state: state, reset_requested: false, should_process: !silent, silent } }];

if ($json.reset_requested) {
  return [{ json: { ok: true, status: 'reset_requested', message: 'Use the local CLI or Supabase RPC reset_thread_escalation to reset this thread.', thread_id: $json.thread_id, channel: $json.channel } }];
}
return [{ json: { ok: true, status: 'silent_already_escalated', response: null, thread_id: $json.thread_id, channel: $json.channel, reset_hint: `select public.reset_thread_escalation('${$json.tenant_id}', '${$json.channel}', '${$json.thread_id}', 'operator', 'handoff complete');` } }];

const req = $('Normalize Internal Test Request').first().json;
const inputItems = typeof $input !== 'undefined' ? $input.all() : [];
const rawDocs = inputItems.flatMap((item) => {
  const value = item && item.json;
  if (Array.isArray(value)) return value;
  if (value && Array.isArray(value.rows)) return value.rows;
  return value ? [value] : [];
});
const docs = rawDocs
  .filter((row) => row && typeof row === 'object' && (row.id || row.chunk_text || row.similarity !== undefined))
  .map((row) => ({
    ...row,
    similarity: Number(row.similarity || 0),
    chunk_text: String(row.chunk_text || row.content || '').trim(),
  }))
  .filter((row) => row.chunk_text.length > 0)
  .sort((a, b) => Number(b.similarity || 0) - Number(a.similarity || 0));

const messageText = String(req.message_text || '').trim();
const lowerMessage = messageText.toLowerCase();
const publicUsdPriceAnchors = [
  ['Quick Workflow Audit', '$165', 'fast diagnosis of one workflow, funnel, bot, or CRM handoff'],
  ['Lead Response / Reply Audit', '$230', 'audit of how inbound leads are answered and where sales are lost'],
  ['Deep Automation Audit', '$360', 'deeper map of automations, risks, priorities, and implementation sequence'],
  ['Content Publishing Automation', '$745', 'automation for publishing or repurposing content across channels'],
  ['API Workflow Build Sprint', '$1,515', 'focused build sprint for one production workflow with API integrations'],
  ['AI Booking + CRM System', '$3,180', 'AI assistant connected to booking, CRM, lead status, and follow-up logic'],
  ['Multi-channel Lead Handling System', '$5,615', 'Instagram/Telegram/other channel lead handling with routing, memory, analytics, and handoff']
];
const publicPriceContext = 'Public USD price anchors for initial sales qualification:\n' + publicUsdPriceAnchors.map((row) => '- ' + row[0] + ' вҖ” ' + row[1] + ': ' + row[2]).join('\n');

function hasCommercialOrOperationalIntent(text) {
  const value = String(text || '');
  return /\b(service|services|offer|offers|package|packages|price|pricing|cost|quote|proposal|budget|website|site|landing|shop|store|ecommerce|build|automation|automate|ai|bot|chatbot|instagram|telegram|crm|lead|leads|sales|funnel|payment|payments|marketplace|content|support|operations|workflow|process|audit|consult|problem|business|company|customer|client|booking|order|integration|api|dm|direct message|reply|inbox)\b/i.test(value)
    || /СғСҒР»СғРі|СҒРөСҖРІРёСҒ|РҝСҖРөРҙР»РҫР¶|РҝР°РәРөСӮ|СҶРөРҪ|РҝСҖР°Р№СҒ|СҒСӮРҫРёРј|РұСҺРҙР¶РөСӮ|СҒР°Р№СӮ|Р»РөРҪРҙРёРҪРі|РјР°РіР°Р·РёРҪ|Р°РІСӮРҫРјР°СӮРёР·Р°СҶ|РұРҫСӮ|СҮР°СӮ.?РұРҫСӮ|РёРҪСҒСӮР°РіСҖР°Рј|СӮРөР»РөРіСҖР°Рј|crm|СҒСҖРј|Р»РёРҙ|РҝСҖРҫРҙР°Р¶|РІРҫСҖРҫРҪРә|РҫРҝР»Р°СӮ|РјР°СҖРәРөСӮРҝР»РөР№СҒ|РәРҫРҪСӮРөРҪСӮ|РҝРҫРҙРҙРөСҖР¶Рә|РҝСҖРҫСҶРөСҒСҒ|РұРёР·РҪРөСҒ|РәРҫРјРҝР°РҪ|РәР»РёРөРҪСӮ|Р·Р°СҸРІРә|Р·Р°РәР°Р·|РёРҪСӮРөРіСҖР°СҶ|api|Р°РҝРё|РҙРёСҖРөРәСӮ|СҒРҫРҫРұСүРөРҪ|РҫСӮРІРөСӮ/i.test(value)
    || /иҮӘеҠЁ|иҮӘеӢ•|жңәеҷЁдәә|ж©ҹеҷЁдәә|е®ўжңҚ|з§ҒдҝЎ|ж¶ҲжҒҜ|жҠҘд»·|е ұеғ№|д»·ж ј|еғ№ж ј|зҪ‘з«ҷ|з¶Із«ҷ|й”Җе”®|йҠ·е”®|е®ўжҲ·|е®ўжҲ¶|зәҝзҙў|з·ҡзҙў|ж”Ҝд»ҳ|жөҒзЁӢ|дёҡеҠЎ|жҘӯеӢҷ|йӣҶжҲҗ/i.test(value)
    || /tб»ұ Д‘б»ҷng|tu dong|bot|chatbot|instagram|telegram|crm|khГЎch hГ ng|khach hang|bГЎo giГЎ|bao gia|giГЎ|gia|website|trang web|lead|bГЎn hГ ng|ban hang|thanh toГЎn|thanh toan|tГӯch hб»Јp|tich hop/i.test(value);
}

function isConversationStarter(text) {
  const value = String(text || '').trim();
  return /^(?:hi|hello|hey|yo)(?:[\s!.?,;:]+|$)/i.test(value)
    || /^good\s*(?:morning|afternoon|evening)(?:[\s!.?,;:]+|$)/i.test(value)
    || /^(?:РҝСҖРёРІРөСӮ|Р·РҙСҖР°РІСҒСӮРІСғР№|Р·РҙСҖР°РІСҒСӮРІСғР№СӮРө|РҙРҫРұСҖСӢР№|РҙРҫРұСҖРҫРө)(?:[\s!.?,;:]+|$)/iu.test(value)
    || /^(?:hola|bonjour|hallo|ciao|xin chao|chao|chГ o)(?:[\s!.?,;:]+|$)/iu.test(value)
    || /^(?:дҪ еҘҪ|жӮЁеҘҪ)(?:[\s!.?,;:пјҢгҖӮпјҒпјҹгҖҒ]+|$)/u.test(value);
}
function hasHardEscalationSignal(text) {
  const value = String(text || '');
  const explicitEnglishHandoff = /\b(human|operator|real person|live agent|escalate|handover|transfer me|connect me|talk to (?:a )?(?:human|person|agent|operator|manager))\b/i.test(value);
  const sensitiveEnglish = /\b(complaint|refund|chargeback|legal|lawyer|lawsuit|contract dispute|angry|urgent|emergency|data deletion|gdpr|privacy request|security incident|account access|password|billing dispute)\b/i.test(value);
  const explicitRussianHandoff = /(?:РҝРҫРҙРәР»СҺСҮ(?:Рё|РёСӮРө)?|РҝРҫР·РҫРІРё(?:СӮРө)?|РҙР°Р№(?:СӮРө)?|РҪСғР¶(?:РөРҪ|РҪР°)|С…РҫСҮСғ|РҝРөСҖРөРІРөРҙ(?:Рё|РёСӮРө)|СҒРҫРөРҙРёРҪ(?:Рё|РёСӮРө)|РҝРөСҖРөРҙР°Р№(?:СӮРө)?|РҝРөСҖРөРҙР°СӮСҢ|РҝРөСҖРөРәР»СҺСҮРё(?:СӮРө)?).{0,50}(?:РҫРҝРөСҖР°СӮРҫСҖ|СҮРөР»РҫРІРөРә|РјРөРҪРөРҙР¶РөСҖ|СҒРҝРөСҶРёР°Р»РёСҒСӮ|Р¶РёРІРҫР№|Р¶РёРІРҫРіРҫ)|(?:РҫРҝРөСҖР°СӮРҫСҖ|СҮРөР»РҫРІРөРә|РјРөРҪРөРҙР¶РөСҖ|СҒРҝРөСҶРёР°Р»РёСҒСӮ).{0,30}(?:РҝРҫР·РІРҫРҪРёСӮ|РҫСӮРІРөСӮРёСӮ|СҒРІСҸР¶РөСӮСҒСҸ|РҪСғР¶РөРҪ|РҪСғР¶РҪР°)/iu.test(value);
  const sensitiveRussian = /Р¶Р°Р»РҫРұ|РІРҫР·РІСҖР°СӮ|СҮР°СҖРҙР¶РұРөРә|СҺСҖРёСҒСӮ|СҒСғРҙ|РҙРҫРіРҫРІРҫСҖ.*СҒРҝРҫСҖ|СҒСҖРҫСҮРҪРҫ|СҚРәСҒСӮСҖРөРҪРҪРҫ|СғРҙР°Р».*РҙР°РҪРҪ|РҝРөСҖСҒРҫРҪР°Р»СҢРҪ.*РҙР°РҪРҪ|РҙРҫСҒСӮСғРҝ.*Р°РәРәР°СғРҪСӮ|РҝР°СҖРҫР»|СҒРҝРҫСҖ.*РҫРҝР»Р°СӮ/iu.test(value);
  const explicitChineseHandoff = /иҪ¬дәәе·Ҙ|иҪүдәәе·Ҙ|дәәе·Ҙе®ўжңҚ|зңҹдәәе®ўжңҚ|жүҫе®ўжңҚ|дәәе·ҘжңҚеҠЎ|дәәе·ҘжңҚеӢҷ/.test(value);
  const sensitiveChinese = /жҠ•иҜү|жҠ•иЁҙ|йҖҖж¬ҫ|зҙ§жҖҘ|з·ҠжҖҘ|жі•еҫӢ|еҫӢеёҲ|еҫӢеё«|йҡҗз§Ғ|йҡұз§Ғ|еҲ йҷӨж•°жҚ®|еҲӘйҷӨиіҮж–ҷ|е®үе…Ё|еҜҶз Ғ|еҜҶзўј/.test(value);
  const explicitVietnameseHandoff = /(?:gбә·p|gap|nГіi chuyб»Үn|noi chuyen|chuyб»ғn|chuyen).{0,40}(?:nhГўn viГӘn|nhan vien|ngЖ°б»қi thбәӯt|nguoi that|tЖ° vбәҘn viГӘn|tu van vien|hб»— trб»Ј viГӘn|ho tro vien)/i.test(value);
  const sensitiveVietnamese = /khiбәҝu nбәЎi|khieu nai|hoГ n tiб»Ғn|hoan tien|khбә©n cбәҘp|khan cap|phГЎp lГҪ|phap ly|riГӘng tЖ°|rieng tu|xГіa dб»Ҝ liб»Үu|xoa du lieu|bбәЈo mбәӯt|bao mat|mбәӯt khбә©u|mat khau/i.test(value);

  return explicitEnglishHandoff || sensitiveEnglish || explicitRussianHandoff || sensitiveRussian || explicitChineseHandoff || sensitiveChinese || explicitVietnameseHandoff || sensitiveVietnamese;
}

function isOffTopicMessage(text) {
  const value = String(text || '');
  if (!value.trim()) return false;
  if (isConversationStarter(value) || hasCommercialOrOperationalIntent(value)) return false;
  return /\b(weather|forecast|temperature|rain|snow|news|sports|football|basketball|movie|recipe|joke|crypto price|bitcoin price|stock price|time now|date today)\b/i.test(value)
