}

function inferLanguageKey(message) {
  const text = String(message || '').trim();
  if ((text.match(/[\u3400-\u9FFF]/g) || []).length >= 2) return 'zh';
  if ((text.match(/[Рҗ-РҜР°-СҸРҒС‘]/g) || []).length >= 2) return 'ru';
  if (/[ДғГўД‘ГӘГҙЖЎЖ°ДӮГӮДҗГҠГ”Ж ЖҜГ ГЎбәЈГЈбәЎбәұбәҜбәібәөбә·бә§бәҘбә©бә«бәӯГЁГ©бә»бәҪбә№б»Ғбәҝб»ғб»…б»ҮГ¬Гӯб»үД©б»ӢГІГіб»ҸГөб»Қб»“б»‘б»•б»—б»ҷб»қб»ӣб»ҹб»Ўб»ЈГ№Гәб»§Е©б»Ҙб»«б»©б»ӯб»Ҝб»ұб»іГҪб»·б»№б»ө]/.test(text)) return 'vi';
  return 'en';
}

function inferResponseLanguage(message) {
  const key = inferLanguageKey(message);
  if (key === 'zh') return 'Chinese/Cantonese matching the customer message';
  if (key === 'ru') return 'Russian';
  if (key === 'vi') return 'Vietnamese';
  return 'English';
}

function inferPreferredCurrency(text) {
  const value = String(text || '');
  const rules = [
    ['USD', /\b(usd|us\s*dollars?|dollars?|usd\$|\$)\b/i],
    ['HKD', /\b(hkd|hk\$|hong\s*kong\s*dollars?)\b|жёҜеёҒ|жёҜе№Ј/i],
    ['EUR', /\b(eur|euro|euros?)\b|вӮ¬/i],
    ['GBP', /\b(gbp|pounds?|sterling)\b|ВЈ/i],
    ['AUD', /\b(aud|australian\s*dollars?)\b/i],
    ['CAD', /\b(cad|canadian\s*dollars?)\b/i],
    ['SGD', /\b(sgd|singapore\s*dollars?)\b/i],
    ['CNY', /\b(cny|rmb|yuan)\b|дәәж°‘еёҒ|дәәж°‘е№Ј/i],
    ['JPY', /\b(jpy|yen)\b|ВҘ/i],
    ['VND', /\b(vnd|dong|vietnamese\s*dong)\b|вӮ«/i],
    ['THB', /\b(thb|baht)\b/i],
    ['AED', /\b(aed|dirham|dirhams)\b/i],
    ['INR', /\b(inr|rupees?)\b/i],
    ['RUB', /\b(rub|rouble|ruble|rubles?)\b|СҖСғРұ|вӮҪ/i],
  ];
  const match = rules.find(([, regex]) => regex.test(value));
  return match ? match[0] : 'USD';
}

