const languageKey = inferLanguageKey(messageText);
const conversationStarter = isConversationStarter(messageText);
const commercialIntent = hasCommercialOrOperationalIntent(lowerMessage);
const hardHandoff = hasHardEscalationSignal(lowerMessage);
const offTopic = isOffTopicMessage(messageText);
const simpleGreeting = conversationStarter && !commercialIntent && messageText.split(/\s+/).filter(Boolean).length <= 3 && messageText.length <= 32;
const preferredCurrency = inferPreferredCurrency(messageText);
const responseLanguage = inferResponseLanguage(messageText);
const confidence = docs.reduce((max, row) => Math.max(max, Number(row.similarity || 0)), 0);

const retrievedContext = docs
  .map((row, index) => {
    const sourceLabel = row.source_key || row.source_type || row.id || ('source_' + (index + 1));
    return 'Source ' + (index + 1) + ': ' + sourceLabel + ' (similarity ' + Number(row.similarity || 0).toFixed(3) + ')\n' + row.chunk_text;
  })
  .join('\n\n---\n\n');

const semanticFallbackContext = [
  'Meaning-first fallback for inbound commercial conversations when Supabase RAG is weak, missing, or not directly matched.',
  publicPriceContext,
  'Primary goal: behave like a capable sales/discovery assistant, not a rigid FAQ bot. Understand the customer intent across any language and keep the conversation moving toward a qualified next step.',
  'Greeting rule: for simple greetings or conversation starters, do not answer generically. Briefly position Sell.Systems around AI automation, sales/CRM workflows, Instagram/Telegram bots, websites/funnels, and lead handling, then ask which area the customer wants to improve first.',
  'Allowed offer families: AI automation, Instagram/Telegram DM assistants, lead-response systems, CRM/workflow automation, websites, landing pages, sales funnels, ecommerce/shop builds, payment flows, content/marketplace operations, and customer-support automations.',
  'Discovery rule: if a customer asks for something broad or unclear, infer the likely business problem, explain the practical outcome in one or two sentences, then ask one concrete qualification question. Do not give up because exact RAG text is missing.',
  'Pricing rule: public initial price anchors are in USD. For pricing questions, name 2-4 relevant USD anchors directly before asking the next scoping question. Do not answer only with вҖңdependsвҖқ.',
  'Currency rule: default public pricing currency is USD for every language. Use another currency only if the customer explicitly asks for that currency. Do not infer currency from language alone, including Chinese/Cantonese. Do not use HKD/HK$/жёҜеёҒ/жёҜе№Ј unless the customer explicitly asks for Hong Kong dollars/HKD/жёҜеёҒ/жёҜе№Ј or says they need Hong Kong-local billing. If retrieved context contains non-USD prices but preferred/requested currency is USD, ignore those non-USD prices and quote the public USD anchors. If exact conversion is not in retrieved context, quote the USD base and say final local-currency invoice can be calculated after scope confirmation.',
  'Topic guardrail: if the message is not clearly related to Sell.Systems services, briefly steer back to automation, websites, bots, or sales systems and ask what business result they want. Do not escalate immediately for normal ambiguity or off-topic small talk.',
  'Escalate only for explicit human handoff requests, legal/refund/complaint/urgent/sensitive account-specific cases, or after repeated failed attempts where the bot cannot safely help.'
].join('\n');

const context = retrievedContext ? (retrievedContext + '\n\n---\n\n' + publicPriceContext) : semanticFallbackContext;
const deterministicReplyText = hardHandoff ? localizedEscalationReply(languageKey) : offTopic ? localizedRedirectReply(languageKey) : simpleGreeting ? localizedGreetingReply(languageKey) : '';

return [{
  json: {
    ...req,
    docs,
    confidence,
    context,
    sales_intent: commercialIntent,
    semantic_fallback_used: !retrievedContext,
    sales_fallback_used: !retrievedContext,
    preferred_currency: preferredCurrency,
    response_language: responseLanguage,
    deterministic_reply_text: deterministicReplyText,
    deterministic_status: hardHandoff ? 'escalated' : 'answered',
    deterministic: !!deterministicReplyText,
    simple_greeting: simpleGreeting,
    requires_handoff: hardHandoff,
    off_topic_redirect: offTopic && !hardHandoff,
    escalation_decision_reason: hardHandoff ? 'explicit_or_sensitive_handoff_signal' : offTopic ? 'off_topic_redirect' : 'answerable_sales_or_discovery',
  }
}];

const req = $('Build Internal Prompt Context').first().json;
const response = $json.choices?.[0]?.message?.content || '';
return [{
  json: {
    ok: true,
    status: 'answered',
    tenant_id: req.tenant_id,
    channel: req.channel,
    thread_id: req.thread_id,
    confidence: req.confidence,
    response_language: req.response_language,
    preferred_currency: req.preferred_currency,
    sales_intent: req.sales_intent,
    semantic_fallback: req.semantic_fallback_used,
    deterministic: false,
    simple_greeting: !!req.simple_greeting,
    requires_handoff: false,
    off_topic_redirect: false,
    escalation_decision_reason: req.escalation_decision_reason || null,
    response,
    matched_sources: Array.isArray(req.docs) ? req.docs.map((row) => ({ source_key: row.source_key, source_type: row.source_type, similarity: row.similarity })) : []
  }
}];
